sql:
SELECT log_message, log_level 
FROM system_logs 
WHERE user_id = 1;

SELECT COUNT(log_id) AS total_info_logs
FROM system_logs
WHERE log_level = 'info';

SELECT AVG(average_speed) 
FROM traffic_conditions 
WHERE traffic_status = 'congested';

SELECT bus_id
FROM bus_positions
WHERE line_id = 1 AND status = 'delayed';

SELECT users.user_name, bus_lines.operational_status
FROM users
INNER JOIN bus_lines ON users.user_id = bus_lines.line_id;

SELECT COUNT(*) 
FROM bus_positions 
WHERE status = 'on schedule';

SELECT line_id, line_name, NTILE(2) OVER (ORDER BY line_id) AS line_group
FROM bus_lines
WHERE operational_status = 'active';

