SELECT landmark_name, distance
FROM bus_stop_landmarks
WHERE distance < 1;

SELECT MIN(location_easting), MIN(location_northing), TAN(location_easting), TAN(location_northing)
FROM bus_stops
WHERE stop_id = 1;
